INSERT INTO public.homonym_questions (id, question, option_a, option_b, option_c, option_d, answer, pair_id)
VALUES
  (1, 'The committee decided to __________ his proposal for the new park, __________ for the section regarding the removal of old trees. (a) except, accept (b) accept, except (c) accept, accept (d) except, except', 'except, accept', 'accept, except', 'accept, accept', 'except, except', 'b', 1),
  (2, 'The marketing team decided to __________ a small discount code to the bottom of the magazine __________ to track how many customers saw it. (a) ad, add (b) add, add (c) add, ad (d) ad, ad', 'ad, add', 'add, add', 'add, ad', 'ad, ad', 'c', 2),
  (3, 'I would strongly __________ you to seek legal __________ before signing a contract that seems so complicated. (a) advise, advice (b) advice, advise (c) advise, advise (d) advice, advice', 'advise, advice', 'advice, advise', 'advise, advise', 'advice, advice', 'a', 3),
  (4, 'The senator’s chief __________ was quick to provide first __________ when a tourist collapsed during the gallery tour. (a) aid, aide (b) aide, aid (c) aid, aid (d) aide, aide', 'aid, aide', 'aide, aid', 'aid, aid', 'aide, aide', 'b', 4),
  (5, 'The old sailor began to __________ after drinking a glass of spoiled __________, which he had found in the ship''s cargo. (a) ale, ail (b) ail, ail (c) ale, ale (d) ail, ale', 'ale, ail', 'ail, ail', 'ale, ale', 'ail, ale', 'd', 5),
  (6, 'The young __________ to the throne stepped out for some fresh __________; however, he was told to return inside __________ the storm began. (a) heir, air, ere (b) air, heir, ere (c) ere, air, heir (d) heir, ere, air', 'heir, air, ere', 'air, heir, ere', 'ere, air, heir', 'heir, ere, air', 'a', 6),
  (7, '__________ be waiting for you in the grocery __________ near the snacks, rather than waiting outside on the cold __________. (a) Isle, aisle, I''ll (b) I''ll, isle, aisle (c) I''ll, aisle, isle (d) Aisle, I''ll, isle', 'Isle, aisle, I''ll', 'I''ll, isle, aisle', 'I''ll, aisle, isle', 'Aisle, I''ll, isle', 'c', 7),
  (8, 'The magician’s performance was a mere __________ of reality, but his script contained a subtle __________ to a famous historical event. (a) allusion, illusion (b) illusion, allusion (c) illusion, illusion (d) allusion, allusion', 'allusion, illusion', 'illusion, allusion', 'illusion, illusion', 'allusion, allusion', 'b', 8),
  (9, 'The priest asked the couple to step closer to the __________; he noted that marriage would __________ their lives forever. (a) alter, altar (b) altar, alter (c) altar, altar (d) alter, alter', 'alter, altar', 'altar, alter', 'altar, altar', 'alter, alter', 'b', 9),
  (10, 'The hungry boy __________ a total of __________ cupcakes before his mother could stop him. (a) eight, ate (b) ate, eight (c) ate, ate (d) eight, eight', 'eight, ate', 'ate, eight', 'ate, ate', 'eight, eight', 'b', 10),
  (11, 'The prisoner''s family struggled to pay the __________, while the farmer worked to tie up the final __________ of hay. (a) bale, bail (b) bail, bail (c) bail, bale (d) bale, bale', 'bale, bail', 'bail, bail', 'bail, bale', 'bale, bale', 'c', 11),
  (12, 'The hiker had to __________ the weight of his heavy pack while walking through the woods with __________ feet because his boots had fallen apart. (a) bare, bear (b) bear, bare (c) bear, bear (d) bare, bare', 'bare, bear', 'bear, bare', 'bear, bear', 'bare, bare', 'b', 12),
  (13, 'The local __________ was __________ from the stadium after they refused to stop playing past the curfew. (a) banned, band (b) band, band (c) band, banned (d) banned, banned', 'banned, band', 'band, band', 'band, banned', 'banned, banned', 'c', 13),
  (14, 'On the __________ of the evidence provided, the umpire ruled that the runner had not touched the __________. (a) basis, bases (b) bases, basis (c) basis, basis (d) bases, bases', 'basis, bases', 'bases, basis', 'basis, basis', 'bases, bases', 'a', 14),
  (15, 'The chef decided to serve a roasted __________ for dinner, but the long day had left him feeling completely __________. (a) beet, beat (b) beat, beet (c) beat, beat (d) beet, beet', 'beet, beat', 'beat, beet', 'beat, beat', 'beet, beet', 'a', 15),
  (16, 'The wind __________ so hard that it knocked over the vase, leaving a bright __________ stain on the white carpet. (a) blue, blew (b) blew, blue (c) blew, blew (d) blue, blue', 'blue, blew', 'blew, blue', 'blew, blew', 'blue, blue', 'b', 16),
  (17, 'The farm __________ many prize-winning horses, but they barely had enough __________ to feed them all during the winter. (a) bread, bred (b) bred, bread (c) bread, bread (d) bred, bred', 'bread, bred', 'bred, bread', 'bread, bread', 'bred, bred', 'b', 17),
  (18, 'The travelers decided to __________ some souvenirs at the shop __________ the road before saying __________ to their guide. (a) by, buy, bye (b) buy, by, bye (c) bye, buy, by (d) buy, bye, by', 'by, buy, bye', 'buy, by, bye', 'bye, buy, by', 'buy, bye, by', 'b', 18),
  (19, 'The politicians met at the __________ in the state __________ to discuss whether the crime should remain a __________ offense. (a) capitol, capital, capital (b) capital, capitol, capital (c) capitol, capitol, capital (d) capital, capital, capitol', 'capitol, capital, capital', 'capital, capitol, capital', 'capitol, capitol, capital', 'capital, capital, capitol', 'a', 19),
  (20, 'The worker was __________ the envelope when he looked up and noticed a leak in the office __________. (a) ceiling, sealing (b) sealing, ceiling (c) sealing, sealing (d) ceiling, ceiling', 'ceiling, sealing', 'sealing, ceiling', 'sealing, sealing', 'ceiling, ceiling', 'b', 20),
  (21, 'If you __________ those stolen goods, you will end up in a prison __________. (a) cell, sell (b) sell, cell (c) cell, cell (d) sell, sell', 'cell, sell', 'sell, cell', 'cell, cell', 'sell, sell', 'b', 21),
  (22, 'The package she __________ contained a candle with a floral __________, but it was missing one __________ from the change she expected. (a) cent, scent, sent (b) sent, scent, cent (c) sent, cent, scent (d) cent, sent, scent', 'cent, scent, sent', 'sent, scent, cent', 'sent, cent, scent', 'cent, sent, scent', 'b', 22),
  (23, 'The detective watched the __________ drama on TV while eating his favorite bowl of sugary __________. (a) serial, cereal (b) cereal, serial (c) cereal, cereal (d) serial, serial', 'serial, cereal', 'cereal, serial', 'cereal, cereal', 'serial, serial', 'a', 23),
  (24, 'You should __________ your food carefully because the puppy __________ everything it finds on the floor. (a) chews, choose (b) choose, chews (c) choose, choose (d) chews, chews', 'chews, choose', 'choose, chews', 'choose, choose', 'chews, chews', 'b', 24),
  (25, 'It was a __________ morning in __________, so we decided to cook a hot pot of __________. (a) chilly, Chile, chili (b) Chile, chilly, chili (c) chilly, chili, Chile (d) Chile, chili, chilly', 'chilly, Chile, chili', 'Chile, chilly, chili', 'chilly, chili, Chile', 'Chile, chili, chilly', 'a', 25),
  (26, 'The musician struck a beautiful __________ on his guitar, which was tied to his case with a sturdy __________. (a) cord, chord (b) chord, cord (c) chord, chord (d) cord, cord', 'cord, chord', 'chord, cord', 'chord, chord', 'cord, cord', 'b', 26),
  (27, 'The historian was able to __________ three sources to prove that this was the exact __________ of the ancient battle. (a) site, cite (b) cite, site (c) cite, cite (d) site, site', 'site, cite', 'cite, site', 'cite, cite', 'site, site', 'b', 27),
  (28, 'Please __________ the door quickly so that you can change your __________ for the party. (a) close, clothes (b) clothes, close (c) close, close (d) clothes, clothes', 'close, clothes', 'clothes, close', 'close, close', 'clothes, clothes', 'a', 28),
  (29, 'The __________ texture of the sand made the hiking __________ much more difficult than we expected. (a) course, coarse (b) coarse, course (c) coarse, coarse (d) course, course', 'course, coarse', 'coarse, course', 'coarse, coarse', 'course, course', 'b', 29),
